class Solution:
    def numberToWords(self, num):
        if num == 0:
            return 'Zero'
        below20 = ['', 'One', 'Two', 'Three', 'Four', 'Five', 'Six', 'Seven',
                   'Eight', 'Nine', 'Ten', 'Eleven', 'Twelve', 'Thirteen',
                   'Fourteen', 'Fifteen', 'Sixteen', 'Seventeen', 'Eighteen',
                   'Nineteen']
        tens = ['', '', 'Twenty', 'Thirty', 'Forty', 'Fifty', 'Sixty',
                'Seventy', 'Eighty', 'Ninety']
        # Independent recursion (no group loop): peel off the biggest scale.
        def helper(n):
            if n == 0:
                return ''
            if n < 20:
                return below20[n]
            if n < 100:
                return (tens[n // 10] + ' ' + helper(n % 10)).strip()
            if n < 1000:
                return (below20[n // 100] + ' Hundred ' + helper(n % 100)).strip()
            if n < 1000000:
                return (helper(n // 1000) + ' Thousand ' + helper(n % 1000)).strip()
            if n < 1000000000:
                return (helper(n // 1000000) + ' Million ' + helper(n % 1000000)).strip()
            return (helper(n // 1000000000) + ' Billion ' + helper(n % 1000000000)).strip()
        return ' '.join(helper(num).split())

