        tens = ['', '', 'Twenty', 'Thirty', 'Forty', 'Fifty', 'Sixty',
                'Seventy', 'Eighty', 'Ninety']
        scales = ['', 'Thousand', 'Million', 'Billion']

        def three(n):
            words = []
            if n >= 100:
                words.append(below20[n // 100])
                words.append('Hundred')
                n %= 100
            if n >= 20:
                words.append(tens[n // 10])
                n %= 10
            if n > 0:
                words.append(below20[n])
            return words

        groups = []
        while num > 0:
            groups.append(num % 1000)
            num //= 1000
        parts = []
        for i in range(len(groups) - 1, -1, -1):
            if groups[i] == 0:
                continue
            parts.extend(three(groups[i]))
            if scales[i]:
                parts.append(scales[i])
        return ' '.join(parts)

